class NetworkInterceptor {
  constructor() {
    this.originalFetch = null;
    this.originalXHROpen = null;
    this.originalXHRSend = null;
    this.isInstalled = false;
    this.requestCounter = 0;
  }

  install() {
    if (this.isInstalled) return;
    this.interceptFetch();
    this.interceptXHR();
    this.isInstalled = true;
    logger.info('NetworkInterceptor', 'Network interceptor installed');
  }

  uninstall() {
    if (!this.isInstalled) return;
    if (this.originalFetch) {
      global.fetch = this.originalFetch;
      this.originalFetch = null;
    }
    if (this.originalXHROpen) {
      XMLHttpRequest.prototype.open = this.originalXHROpen;
      this.originalXHROpen = null;
    }
    if (this.originalXHRSend) {
      XMLHttpRequest.prototype.send = this.originalXHRSend;
      this.originalXHRSend = null;
    }
    this.isInstalled = false;
    logger.info('NetworkInterceptor', 'Network interceptor uninstalled');
  }

  interceptFetch() {
    this.originalFetch = global.fetch;
    const self = this;

    global.fetch = async function (...args) {
      const requestId = `fetch_${++self.requestCounter}`;
      const startTime = Date.now();
      const [input, init = {}] = args;

      const url = typeof input === 'string' ? input : input?.url || 'unknown';
      const method = init.method || (typeof input === 'object' ? input.method : 'GET') || 'GET';
      const contentType = init.headers?.['Content-Type'] || init.headers?.['content-type'] || '';

      logger.info('Network', 'Request started', {
        requestId,
        method: method.toUpperCase(),
        url: sanitizeUrl(url),
        headers: sanitizeHeaders(init.headers || {}),
        bodyPreview: sanitizeRequestBody(init.body, contentType),
      });

      try {
        const response = await self.originalFetch.apply(this, args);
        const duration = Date.now() - startTime;

        // Clone response to read body without consuming it
        const cloned = response.clone();
        let responseBodyPreview;
        try {
          const responseText = await cloned.text();
          try {
            const parsed = JSON.parse(responseText);
            responseBodyPreview = sanitizeValue(parsed);
          } catch {
            responseBodyPreview = truncateString(redactPIIFromString(responseText), 256);
          }
        } catch {
          responseBodyPreview = '[UNABLE_TO_READ_RESPONSE]';
        }

        const logData = {
          requestId,
          method: method.toUpperCase(),
          url: sanitizeUrl(url),
          status: response.status,
          statusText: response.statusText,
          duration: `${duration}ms`,
          responseHeaders: sanitizeHeaders(Object.fromEntries(response.headers?.entries?.() || [])),
          responsePreview: responseBodyPreview,
        };

        if (response.status >= 400) {
          logger.warn('Network', `Request failed: ${method.toUpperCase()} ${sanitizeUrl(url)} -> ${response.status}`, logData);
        } else {
          logger.info('Network', `Request completed: ${method.toUpperCase()} ${sanitizeUrl(url)} -> ${response.status}`, logData);
        }

        return response;
      } catch (error) {
        const duration = Date.now() - startTime;
        logger.error('Network', `Request error: ${method.toUpperCase()} ${sanitizeUrl(url)}`, {
          requestId,
          method: method.toUpperCase(),
          url: sanitizeUrl(url),
          duration: `${duration}ms`,
          error: {
            name: error.name,
            message: redactPIIFromString(error.message),
          },
        });
        throw error;
      }
    };
  }

  interceptXHR() {
    this.originalXHROpen = XMLHttpRequest.prototype.open;
    this.originalXHRSend = XMLHttpRequest.prototype.send;
    const self = this;

    XMLHttpRequest.prototype.open = function (method, url, ...rest) {
      this._debugMethod = method;
      this._debugUrl = url;
      this._debugRequestId = `xhr_${++self.requestCounter}`;
      this._debugStartTime = Date.now();
      return self.originalXHROpen.apply(this, [method, url, ...rest]);
    };

    XMLHttpRequest.prototype.send = function (body) {
      const xhr = this;

      logger.info('Network', 'XHR Request started', {
        requestId: xhr._debugRequestId,
        method: (xhr._debugMethod || 'GET').toUpperCase(),
        url: sanitizeUrl(xhr._debugUrl),
        bodyPreview: sanitizeRequestBody(body),
      });

      const originalOnReadyStateChange = xhr.onreadystatechange;
      xhr.onreadystatechange = function (...args) {
        if (xhr.readyState === 4) {
          const duration = Date.now() - (xhr._debugStartTime || 0);
          let responsePreview;
          try {
            if (xhr.responseText) {
              try {
                const parsed = JSON.parse(xhr.responseText);
                responsePreview = sanitizeValue(parsed);
              } catch {
                responsePreview = truncateString(redactPIIFromString(xhr.responseText), 256);
              }
            }
          } catch {
            responsePreview = '[UNABLE_TO_READ_RESPONSE]';
          }

          const logData = {
            requestId: xhr._debugRequestId,
            method: (xhr._debugMethod || 'GET').toUpperCase(),
            url: sanitizeUrl(xhr._debugUrl),
            status: xhr.status,
            duration: `${duration}ms`,
            responsePreview,
          };

          if (xhr.status >= 400 || xhr.status === 0) {
            logger.warn('Network', `XHR failed: ${(xhr._debugMethod || 'GET').toUpperCase()} -> ${xhr.status}`, logData);
          } else {
            logger.info('Network', `XHR completed: ${(xhr._debugMethod || 'GET').toUpperCase()} -> ${xhr.status}`, logData);
          }
        }
        if (originalOnReadyStateChange) {
          originalOnReadyStateChange.apply(this, args);
        }
      };

      return self.originalXHRSend.apply(this, [body]);
    };
  }
}

